// Parse AI response
const content = $input.first().json.content[0].text;
let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  parsed = { score: 50, reason: 'Parse error — review manually', flag: 'yellow' };
}
return [{
  json: {
    application_id: $('Parse Application').first().json.id,
    aiScore: parsed.score,
    ai_reason: parsed.reason,
    ai_flag: parsed.flag
  }
}];
